    case 'FETCH_START': return { ...state, loading: true };
    case 'FETCH_SUCCESS': return { ...state, loading: false, data: action.data };
    case 'FETCH_ERROR': return { ...state, loading: false, error: action.error };
    default: return state;
  }
}

