  useEffect(() => {
    let cancelled = false;
    dispatch({ type: 'FETCH_START' });
    fetch(url)
      .then(r => r.json())
      .then(data => { if (!cancelled) dispatch({ type: 'FETCH_SUCCESS', data }); })
      .catch(error => { if (!cancelled) dispatch({ type: 'FETCH_ERROR', error: error.message }); });
    return () => { cancelled = true; };
  }, [url]);
  return state;
}

