// Typed cache
class TypedCache<K extends string, V> {
  private cache = new Map<K, V>();
  set(key: K, value: V) { this.cache.set(key, value); }
  get(key: K): V | undefined { return this.cache.get(key); }
}

const userCache = new TypedCache<string, User>();

function getUser(id: string): User | Promise<User> {
  const cached = userCache.get(id);
  if (cached) return cached;
  return fetchUser(id).then(u => {
    userCache.set(id, u);
    return u;
  });
}

